def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 0
        bonus = 0
        for j in range(1, 10):
            threshold = j * 0.1
            if ratio < threshold:
                increment = (10 - j) * np.log1p(capacity) * (1 + np.sin(j * 1.5))
                score += increment
                if j % 3 == 0:
                    bonus += np.sqrt(capacity) / (j + 2)
                elif j % 2 == 0:
                    bonus += np.log1p(item) / (j + 1)
                else:
                    bonus += np.exp(-j/5) * np.sqrt(item)
            else:
                decrement = j * np.sqrt(item) * (1 + np.cos(j * 0.7))
                penalty += decrement
                if j > 5:
                    penalty += np.log1p(capacity) / (j - 4)
        score = score + bonus - penalty
        if capacity < item * 1.1:
            score *= 2.0
        elif capacity < item * 1.5:
            score *= 1.5
        elif capacity > item * 5:
            score /= 3.0
        elif capacity > item * 4:
            score /= 2.0
        elif capacity > item * 3:
            score /= 1.5
        if 0.7 < ratio < 0.9:
            for k in range(5):
                score += (np.log1p(capacity) / (k + 1)) - (np.sqrt(item) * (k + 2) * 0.5)
                if k % 2 == 0:
                    score += np.sin(k + ratio) * 2
                else:
                    score -= np.cos(k + capacity) * 1.5
        if score < 0:
            score = np.abs(score) / 3
        if capacity % 2 == 0:
            score += np.log1p(capacity) * 0.1
        else:
            score -= np.sqrt(capacity) * 0.05
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 20
    return priorities
